class SSRFProtectionError(Exception):
    """Raised when a URL fails SSRF validation."""
    pass


class SSRFValidator:
    """
    Comprehensive SSRF protection validator.

    Validates URLs against multiple security checks:
    1. Scheme validation (only http/https)
    2. Domain allowlist/blocklist checking
    3. DNS resolution with IP validation
    4. Private/internal IP range blocking
    5. Port restriction
    6. Redirect validation
    """

    # Private and reserved IP ranges that must be blocked
    BLOCKED_IP_NETWORKS = [
        # Loopback
        ipaddress.ip_network("127.0.0.0/8"),
        ipaddress.ip_network("::1/128"),

        # Link-local
        ipaddress.ip_network("169.254.0.0/16"),
        ipaddress.ip_network("fe80::/10"),

        # Private ranges (RFC 1918)
        ipaddress.ip_network("10.0.0.0/8"),
        ipaddress.ip_network("172.16.0.0/12"),
        ipaddress.ip_network("192.168.0.0/16"),

        # Unique local (IPv6)
        ipaddress.ip_network("fc00::/7"),

        # Multicast
        ipaddress.ip_network("224.0.0.0/4"),
        ipaddress.ip_network("ff00::/8"),

        # AWS metadata service
        ipaddress.ip_network("169.254.169.254/32"),

        # Cloud metadata endpoints
        ipaddress.ip_network("100.100.100.200/32"),  # Alibaba Cloud
        ipaddress.ip_network("192.0.0.192/32"),       # Oracle Cloud

        # Reserved
        ipaddress.ip_network("0.0.0.0/8"),
        ipaddress.ip_network("192.0.2.0/24"),         # TEST-NET-1
        ipaddress.ip_network("198.51.100.0/24"),       # TEST-NET-2
        ipaddress.ip_network("203.0.113.0/24"),        # TEST-NET-3
        ipaddress.ip_network("240.0.0.0/4"),           # Reserved
        ipaddress.ip_network("255.255.255.255/32"),    # Broadcast
    ]

    def __init__(self, config: Config):
        self.config = config
        self._dns_resolver = dns.resolver.Resolver()
        self._dns_resolver.timeout = 5
        self._dns_resolver.lifetime = 5
        # Use system DNS or configure specific DNS servers
        # self._dns_resolver.nameservers = ['8.8.8.8', '8.8.4.4']

    def validate_url(self, url: str) -> Tuple[str, str, list]:
        """
        Validate a URL for SSRF safety.

        Returns:
            Tuple of (validated_url, hostname, resolved_ips)

        Raises:
            SSRFProtectionError: If the URL fails any security check.
        """
        logger.info(f"Validating URL: {url}")

        # Step 1: Parse and validate URL structure
        parsed = self._validate_url_structure(url)

        # Step 2: Validate scheme
        self._validate_scheme(parsed)

        # Step 3: Extract and validate hostname
        hostname = self._extract_hostname(parsed)

        # Step 4: Validate port
        port = self._validate_port(parsed)

        # Step 5: Check domain allowlist/blocklist
        self._validate_domain(hostname)

        # Step 6: Check if hostname is a raw IP address
        self._check_raw_ip(hostname)

        # Step 7: Resolve DNS and validate all resolved IPs
        resolved_ips = self._resolve_and_validate_dns(hostname)

        # Step 8: Reconstruct validated URL
        validated_url = self._reconstruct_url(parsed)

        logger.info(
            f"URL validated successfully: {validated_url} -> "
            f"{[str(ip) for ip in resolved_ips]}"
        )

        return validated_url, hostname, resolved_ips

    def validate_ip_address(self, ip_str: str) -> None:
        """
        Validate that an IP address is not in any blocked range.

        Raises:
            SSRFProtectionError: If the IP is in a blocked range.
        """
        try:
            ip = ipaddress.ip_address(ip_str)
        except ValueError:
            raise SSRFProtectionError(f"Invalid IP address: {ip_str}")

        # Check if IP is private (covers most cases)
        if ip.is_private:
            raise SSRFProtectionError(
                f"IP address {ip_str} is in a private range"
            )

        # Check if IP is loopback
        if ip.is_loopback:
            raise SSRFProtectionError(
                f"IP address {ip_str} is a loopback address"
            )

        # Check if IP is link-local
        if ip.is_link_local:
            raise SSRFProtectionError(
                f"IP address {ip_str} is a link-local address"
            )

        # Check if IP is multicast
        if ip.is_multicast:
            raise SSRFProtectionError(
                f"IP address {ip_str} is a multicast address"
            )

        # Check if IP is reserved
        if ip.is_reserved:
            raise SSRFProtectionError(
                f"IP address {ip_str} is a reserved address"
            )

        # Check if IP is unspecified (0.0.0.0)
        if ip.is_unspecified:
            raise SSRFProtectionError(
                f"IP address {ip_str} is an unspecified address"
            )

        # Explicit check against all blocked networks
        for network in self.BLOCKED_IP_NETWORKS:
            if ip in network:
                raise SSRFProtectionError(
                    f"IP address {ip_str} is in blocked network {network}"
                )

    def _validate_url_structure(self, url: str):
        """Validate basic URL structure."""
        if not url or not isinstance(url, str):
            raise SSRFProtectionError("URL must be a non-empty string")

        # Limit URL length
        if len(url) > 2048:
            raise SSRFProtectionError("URL exceeds maximum length of 2048 characters")

        # Block URLs with embedded credentials
        if "@" in url.split("//", 1)[-1].split("/", 1)[0]:
            raise SSRFProtectionError("URLs with embedded credentials are not allowed")

        # Block backslash tricks
        if "\\" in url:
            raise SSRFProtectionError("URLs with backslashes are not allowed")

        # Block null bytes
        if "\x00" in url:
            raise SSRFProtectionError("URLs with null bytes are not allowed")

        try:
            parsed = urlparse(url)
        except Exception as e:
            raise SSRFProtectionError(f"Failed to parse URL: {e}")

        if not parsed.hostname:
            raise SSRFProtectionError("URL must contain a valid hostname")

        return parsed

    def _validate_scheme(self, parsed):
        """Validate URL scheme."""
        scheme = parsed.scheme.lower()
        if scheme not in self.config.ALLOWED_SCHEMES:
            raise SSRFProtectionError(
                f"Scheme '{scheme}' is not allowed. "
                f"Allowed schemes: {self.config.ALLOWED_SCHEMES}"
            )

    def _extract_hostname(self, parsed) -> str:
        """Extract and normalize hostname."""
        hostname = parsed.hostname.lower().strip(".")

        if not hostname:
            raise SSRFProtectionError("Empty hostname")

        # Block hostnames that are just whitespace or special characters
        if not re.match(r'^[a-zA-Z0-9\-\.]+$', hostname) and not self._is_ip_address(hostname):
            raise SSRFProtectionError(f"Invalid hostname characters: {hostname}")

        return hostname

    def _validate_port(self, parsed) -> Optional[int]:
        """Validate port number."""
        port = parsed.port

        if port is None:
            # Default ports based on scheme
            return 443 if parsed.scheme == "https" else 80

        if port in self.config.BLOCKED_PORTS:
            raise SSRFProtectionError(f"Port {port} is blocked")

        if self.config.ALLOWED_PORTS and port not in self.config.ALLOWED_PORTS:
            raise SSRFProtectionError(
                f"Port {port} is not in the allowed ports list: "
                f"{self.config.ALLOWED_PORTS}"
            )

        return port

    def _validate_domain(self, hostname: str):
        """Validate domain against allowlist and blocklist."""
        # Check blocklist first
        for blocked in self.config.BLOCKED_DOMAINS:
            if hostname == blocked or hostname.endswith(f".{blocked}"):
                raise SSRFProtectionError(
                    f"Domain '{hostname}' is blocked"
                )

        # Check allowlist if configured
        if self.config.ALLOWED_DOMAINS:
            allowed = False
            for domain in self.config.ALLOWED_DOMAINS:
                if hostname == domain or hostname.endswith(f".{domain}"):
                    allowed = True
                    break
            if not allowed:
                raise SSRFProtectionError(
                    f"Domain '{hostname}' is not in the allowlist"
                )

    def _is_ip_address(self, hostname: str) -> bool:
        """Check if hostname is an IP address."""
        try:
            ipaddress.ip_address(hostname)
            return True
        except ValueError:
            return False

    def _check_raw_ip(self, hostname: str):
        """
        If the hostname is a raw IP address, validate it directly.
        Also check for IP address obfuscation techniques.
        """
        # Check for decimal IP notation (e.g., 2130706433 = 127.0.0.1)
        try:
            if hostname.isdigit():
                decimal_ip = int(hostname)
                if 0 <= decimal_ip <= 0xFFFFFFFF:
                    ip_str = str(ipaddress.ip_address(decimal_ip))
                    self.validate_ip_address(ip_str)
                    return
        except (ValueError, OverflowError):
            pass

        # Check for hex IP notation
        if hostname.startswith("0x"):
            try:
                decimal_ip = int(hostname, 16)
                if 0 <= decimal_ip <= 0xFFFFFFFF:
                    ip_str = str(ipaddress.ip_address(decimal_ip))
                    self.validate_ip_address(ip_str)
                    return
            except (ValueError, OverflowError):
                pass

        # Check for octal IP notation (e.g., 0177.0.0.1 = 127.0.0.1)
        if re.match(r'^0\d', hostname):
            raise SSRFProtectionError(
                "Octal IP notation is not allowed"
            )

        # Standard IP address check
        try:
            ip = ipaddress.ip_address(hostname)
            self.validate_ip_address(str(ip))
        except ValueError:
            # Not an IP address, that's fine - it's a hostname
            pass

    def _resolve_and_validate_dns(self, hostname: str) -> list:
        """
        Resolve hostname via DNS and validate all resolved IP addresses.

        This is critical: we resolve the DNS ourselves and check every
        resolved IP, rather than relying on URL string checks alone.
        """
        # If it's already an IP, just validate it
        try:
            ip = ipaddress.ip_address(hostname)
            self.validate_ip_address(str(ip))
            return [ip]
        except ValueError:
            pass

        resolved_ips = []

        # Resolve A records (IPv4)
        try:
            answers = self._dns_resolver.resolve(hostname, "A")
            for rdata in answers:
                ip_str = str(rdata)
                self.validate_ip_address(ip_str)
                resolved_ips.append(ipaddress.ip_address(ip_str))
        except (dns.resolver.NXDOMAIN, dns.resolver.NoAnswer):
            pass
        except dns.resolver.NoNameservers:
            raise SSRFProtectionError(
                f"DNS resolution failed for {hostname}: no nameservers"
            )
        except dns.exception.Timeout:
            raise SSRFProtectionError(
                f"DNS resolution timed out for {hostname}"
            )

        # Resolve AAAA records (IPv6)
        try:
            answers = self._dns_resolver.resolve(hostname, "AAAA")
            for rdata in answers:
                ip_str = str(rdata)
                self.validate_ip_address(ip_str)
                resolved_ips.append(ipaddress.ip_address(ip_str))
        except (dns.resolver.NXDOMAIN, dns.resolver.NoAnswer,
                dns.resolver.NoNameservers, dns.exception.Timeout):
            pass

        if not resolved_ips:
            raise SSRFProtectionError(
                f"Could not resolve hostname: {hostname}"
            )

        # Check for DNS rebinding: resolve again and compare
        second_resolved = []
        try:
            answers = self._dns_resolver.resolve(hostname, "A")
            for rdata in answers:
                ip_str = str(rdata)
                self.validate_ip_address(ip_str)
                second_resolved.append(ipaddress.ip_address(ip_str))
        except Exception:
            pass

        # If second resolution gives different IPs, validate those too
        for ip in second_resolved:
            if ip not in resolved_ips:
                self.validate_ip_address(str(ip))
                resolved_ips.append(ip)

        return resolved_ips

    def _reconstruct_url(self, parsed) -> str:
        """Reconstruct a clean URL from parsed components."""
        scheme = parsed.scheme.lower()
        hostname = parsed.hostname.lower()
        port = parsed.port
        path = parsed.path or "/"
        query = parsed.query

        # Reconstruct
        url = f"{scheme}://{hostname}"
        if port and not (
            (scheme == "http" and port == 80) or
            (scheme == "https" and port == 443)
        ):
            url += f":{port}"
        url += path
        if query:
            url += f"?{query}"

        return url


