class ScreenshotService:
    """
    Service for capturing website screenshots using headless Chrome.
    """

    def __init__(self, config: Config):
        self.config = config
        self.s3_client = boto3.client("s3", region_name=config.S3_REGION)

    def _create_chrome_options(self) -> Options:
        """Create secure Chrome options for headless browsing."""
        options = Options()

        # Headless mode
        options.add_argument("--headless=new")

        # Security hardening
        options.add_argument("--no-sandbox")
        options.add_argument("--disable-dev-shm-usage")
        options.add_argument("--disable-gpu")
        options.add_argument("--disable-extensions")
        options.add_argument("--disable-plugins")
        options.add_argument("--disable-software-rasterizer")

        # Disable features that could be used for SSRF
        options.add_argument("--disable-background-networking")
        options.add_argument("--disable-default-apps")
        options.add_argument("--disable-sync")
        options.add_argument("--disable-translate")
        options.add_argument("--disable-web-security=false")

        # Disable file access
        options.add_argument("--disable-file-system")
        options.add_argument("--disable-local-storage")

        # Disable JavaScript popups and notifications
        options.add_argument("--disable-notifications")
        options.add_argument("--disable-popup-blocking")

        # Set window size
        options.add_argument(
            f"--window-size={self.config.SCREENSHOT_WIDTH},"
            f"{self.config.SCREENSHOT_HEIGHT}"
        )

        # Set user agent
        options.add_argument(
            "--user-agent=Mozilla/5.0 (X11; Linux x86_64) "
            "AppleWebKit/537.36 (KHTML, like Gecko) "
            "Chrome/120.0.0.0 Safari/537.36 ScreenshotBot/1.0"
        )

        # Disable loading of images for faster screenshots (optional)
        # options.add_argument("--blink-settings=imagesEnabled=false")

        # Set Chrome binary location
        if self.config.CHROME_BINARY:
            options.binary_location = self.config.CHROME_BINARY

        return options

    def capture_screenshot(self, validated_url: str, resolved_ips: list) -> str:
        """
        Capture a screenshot of the validated URL.

        Args:
            validated_url: The SSRF-validated URL to screenshot.
            resolved_ips: Pre-resolved IP addresses for the URL.

        Returns:
            Path to the generated thumbnail file.

        Raises:
            WebDriverException: If Chrome fails to capture the screenshot.
        """
        driver = None
        screenshot_path = None
        thumbnail_path = None

        try:
            options = self._create_chrome_options()

            # Use host-resolver-rules to pin DNS resolution to our validated IPs
            # This prevents DNS rebinding attacks during the actual page load
            parsed = urlparse(validated_url)
            hostname = parsed.hostname
            if resolved_ips:
                # Pin the hostname to the first validated IP
                ip_str = str(resolved_ips[0])
                options.add_argument(
                    f"--host-resolver-rules=MAP {hostname} {ip_str}"
                )
                logger.info(f"Pinned DNS: {hostname} -> {ip_str}")

            service = Service(executable_path=self.config.CHROMEDRIVER_PATH)
            driver = webdriver.Chrome(service=service, options=options)

            # Set timeouts
            driver.set_page_load_timeout(self.config.PAGE_LOAD_TIMEOUT)
            driver.set_script_timeout(self.config.PAGE_LOAD_TIMEOUT)
            driver.implicitly_wait(5)

            # Navigate to the URL
            logger.info(f"Navigating to: {validated_url}")
            driver.get(validated_url)

            # Wait for page to stabilize
            time.sleep(2)

            # Verify the final URL after any redirects
            final_url = driver.current_url
            if final_url != validated_url:
                logger.warning(
                    f"Page redirected: {validated_url} -> {final_url}"
                )
                # Re-validate the final URL after redirect
                ssrf_validator = SSRFValidator(Config())
                ssrf_validator.validate_url(final_url)
                logger.info(f"Redirect target validated: {final_url}")

            # Take screenshot
            screenshot_path = tempfile.mktemp(suffix=".png")
            driver.save_screenshot(screenshot_path)
            logger.info(f"Screenshot saved: {screenshot_path}")

            # Generate thumbnail
            thumbnail_path = self._generate_thumbnail(screenshot_path)
            logger.info(f"Thumbnail generated: {thumbnail_path}")

            return thumbnail_path

        except TimeoutException:
            raise WebDriverException(
                f"Page load timed out after {self.config.PAGE_LOAD_TIMEOUT}s"
            )
        finally:
            if driver:
                try:
                    driver.quit()
                except Exception as e:
                    logger.warning(f"Error closing Chrome: {e}")

            # Clean up screenshot (keep thumbnail)
            if screenshot_path and os.path.exists(screenshot_path):
                try:
                    os.unlink(screenshot_path)
                except OSError:
                    pass

    def _generate_thumbnail(self, screenshot_path: str) -> str:
        """Generate a thumbnail from the full screenshot."""
        thumbnail_path = tempfile.mktemp(suffix=".jpg")

        with Image.open(screenshot_path) as img:
            # Calculate aspect ratio preserving resize
            img.thumbnail(
                (self.config.THUMBNAIL_WIDTH, self.config.THUMBNAIL_HEIGHT),
                Image.Resampling.LANCZOS,
            )

            # Save as JPEG with quality setting
            img.save(
                thumbnail_path,
                "JPEG",
                quality=self.config.SCREENSHOT_QUALITY,
                optimize=True,
            )

        return thumbnail_path

    def upload_to_s3(self, file_path: str, original_url: str) -> str:
        """
        Upload thumbnail to S3 and return the S3 URL.

        Args:
            file_path: Path to the thumbnail file.
            original_url: The original URL that was screenshotted.

        Returns:
            The S3 URL of the uploaded thumbnail.
        """
        # Generate unique key
        file_id = str(uuid.uuid4())
        s3_key = f"{self.config.S3_PREFIX}{file_id}.jpg"

        try:
            self.s3_client.upload_file(
                file_path,
                self.config.S3_BUCKET,
                s3_key,
                ExtraArgs={
                    "ContentType": "image/jpeg",
                    "CacheControl": "public, max-age=86400",
                    "Metadata": {
                        "source-url": original_url[:256],  # Limit metadata size
                        "created-by": "screenshot-service",
                    },
                },
            )

            # Generate presigned URL or construct public URL
            s3_url = (
                f"https://{self.config.S3_BUCKET}.s3."
                f"{self.config.S3_REGION}.amazonaws.com/{s3_key}"
            )

            logger.info(f"Uploaded to S3: {s3_url}")
            return s3_url

        finally:
            # Clean up local file
            if os.path.exists(file_path):
                try:
                    os.unlink(file_path)
                except OSError:
                    pass


