def require_api_key(f):
    """Decorator to require API key authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if config.API_KEY:
            api_key = request.headers.get("X-API-Key", "")
            if api_key != config.API_KEY:
                return jsonify({
                    "error": "Unauthorized",
                    "message": "Invalid or missing API key",
                }), 401
        return f(*args, **kwargs)
    return decorated


def get_client_ip() -> str:
    """Get the client's IP address, considering proxies."""
    # In production behind a load balancer, use X-Forwarded-For
    # but validate it's from a trusted proxy
    forwarded_for = request.headers.get("X-Forwarded-For", "")
    if forwarded_for:
        # Take the first IP (client IP)
        return forwarded_for.split(",")[0].strip()
    return request.remote_addr or "unknown"


@app.route("/health", methods=["GET"])
def health_check():
    """Health check endpoint."""
    return jsonify({"status": "healthy", "service": "screenshot-service"}), 200


@app.route("/api/v1/screenshot", methods=["POST"])
@require_api_key
def create_screenshot():
    """
    Create a screenshot of the provided URL.

    Request body:
        {
            "url": "https://example.com"
        }

    Response:
        {
            "success": true,
            "screenshot_url": "https://bucket.s3.region.amazonaws.com/screenshots/uuid.jpg",
            "original_url": "https://example.com"
        }
    """
    client_ip = get_client_ip()

    # Rate limiting
    if not rate_limiter.is_allowed(client_ip):
        logger.warning(f"Rate limit exceeded for {client_ip}")
        return jsonify({
            "error": "Rate limit exceeded",
            "message": "Too many requests. Please try again later.",
        }), 429

    # Parse request
    data = request.get_json(silent=True)
    if not data or "url" not in data:
        return jsonify({
            "error": "Bad request",
            "message": "Request body must contain a 'url' field.",
        }), 400

    url = data["url"]

    # Input type validation
    if not isinstance(url, str):
        return jsonify({
            "error": "Bad request",
            "message": "URL must be a string.",
        }), 400

    # Strip whitespace
    url = url.strip()

    try:
        # Step 1: SSRF Validation
        validated_url, hostname, resolved_ips = ssrf_validator.validate_url(url)
        logger.info(
            f"Request from {client_ip}: URL validated: {validated_url}"
        )

        # Step 2: Capture screenshot
        thumbnail_path = screenshot_service.capture_screenshot(
            validated_url, resolved_ips
        )

        # Step 3: Upload to S3
        s3_url = screenshot_service.upload_to_s3(thumbnail_path, validated_url)

        return jsonify({
            "success": True,
            "screenshot_url": s3_url,
            "original_url": validated_url,
        }), 200

    except SSRFProtectionError as e:
        logger.warning(
            f"SSRF protection blocked request from {client_ip}: "
            f"URL={url}, reason={str(e)}"
        )
        return jsonify({
            "error": "URL validation failed",
            "message": "The provided URL is not allowed.",
        }), 403

    except WebDriverException as e:
        logger.error(f"Screenshot capture failed: {e}")
        return jsonify({
            "error": "Screenshot failed",
            "message": "Failed to capture screenshot. The page may be "
                       "unavailable or took too long to load.",
        }), 502

    except Exception as e:
        logger.exception(f"Unexpected error processing request: {e}")
        return jsonify({
            "error": "Internal server error",
            "message": "An unexpected error occurred.",
        }), 500


@app.route("/api/v1/validate", methods=["POST"])
@require_api_key
def validate_url():
    """
    Validate a URL without taking a screenshot.
    Useful for pre-validation in the frontend.

    Request body:
        {
            "url": "https://example.com"
        }

    Response:
        {
            "valid": true,
            "validated_url": "https://example.com/",
            "hostname": "example.com"
        }
    """
    data = request.get_json(silent=True)
    if not data or "url" not in data:
        return jsonify({
            "error": "Bad request",
            "message": "Request body must contain a 'url' field.",
        }), 400

    url = data["url"]
    if not isinstance(url, str):
        return jsonify({
            "error": "Bad request",
            "message": "URL must be a string.",
        }), 400

    url = url.strip()

    try:
        validated_url, hostname, resolved_ips = ssrf_validator.validate_url(url)
        return jsonify({
            "valid": True,
            "validated_url": validated_url,
            "hostname": hostname,
            "resolved_ips": [str(ip) for ip in resolved_ips],
        }), 200

    except SSRFProtectionError as e:
        return jsonify({
            "valid": False,
            "error": str(e),
        }), 200


